import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import org.owasp.esapi.ESAPI;

public class XssSafeServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String safeUserInput = ESAPI.encoder().encodeForHTML(userInput); // Encode user input

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<head><title>XSS Safe Page</title></head>");
        out.println("<body>");
        out.println("<h1>Hello, " + safeUserInput + "</h1>"); // Embed encoded user input in the HTML response
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
